-- FSI_DEMO_DB.BANKING.CREDIT_APPLICATIONS

CREATE OR REPLACE TABLE FSI_DEMO_DB.BANKING.CREDIT_APPLICATIONS (

    APPLICATION_ID VARCHAR(20) NOT NULL,
    CUSTOMER_ID VARCHAR(20),
    APPLICATION_DATE DATE,
    PRODUCT_TYPE VARCHAR(50),
    REQUESTED_AMOUNT NUMBER(15,2),
    APPROVED_AMOUNT NUMBER(15,2),
    INTEREST_RATE_OFFERED NUMBER(5,4),
    TERM_MONTHS NUMBER(5,0),
    APPLICATION_STATUS VARCHAR(30),
    DECISION_DATE DATE,
    CREDIT_SCORE NUMBER(3,0),
    DEBT_TO_INCOME_RATIO NUMBER(5,4),
    EMPLOYMENT_LENGTH_YEARS NUMBER(3,1),
    HOME_OWNERSHIP VARCHAR(20),
    PURPOSE VARCHAR(100),
    REJECTION_REASON VARCHAR(200),
    RISK_GRADE VARCHAR(5),
    DEFAULT_PROBABILITY NUMBER(5,4),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (APPLICATION_ID)

);



